form:Form.form:Scripts:
		function LoadForm()
{    
  SetEdad(); 
  if (Ctrl('main').GetMode()!="LIST")  
  	SetEstado();

  if (Ctrl('main').GetMode()=="SHOW")
  {
    //Activo
    if (Ctrl('c_estado').GetXValue() == "A")
    {
      CtrlEnabled('INACTIVO',true);
      CtrlEnabled('ACTIVO',false); 
    }
    else
    //Inactivo
    {
      CtrlEnabled('ACTIVO',true);
      CtrlEnabled('INACTIVO',false);
    }
  }
  if (Ctrl('main').GetMode()=="LIST")
  {
    //Activo
    if (Ctrl('LIST').GetSelectAttrValue('c_estado') == "A") 
    {
      CtrlEnabled('INACTIVO',true);
      CtrlEnabled('ACTIVO',false);
    }
    else //Inactivo
    {
      CtrlEnabled('ACTIVO',true);
      CtrlEnabled('INACTIVO',false);
    }
  }
} 

function SetEstado()  
{
	Ctrl("f_estado").SetXValue(datetime2str(new Date()));
}

function codigocv()
	{
		var datos = Ctrl("oi_tipo_documento").GetCValue().split(' - ');
		Ctrl("c_cv").SetCValue(datos[0]+Ctrl('c_nro_doc').GetCValue());
	}

function SetCuil()
{
	if (Ctrl('c_nro_cuil'))
	{
		Ctrl('c_nro_cuil_hid').SetXValue(Ctrl('c_nro_cuil').GetXValue());
		if (Ctrl('c_nro_cuil').GetXValue()!='')
		{
		  var cuilRes;  
		  var nSQL = GetProxy().SQLService();
		  cuilRes = nSQL.GetOBJ(Ctrl("main").getResource("QRY_VAL_CUIL"), "<PARAM c_nro_cuil=\""+Ctrl('c_nro_cuil_hid').GetCValue()+"\" c_nro_doc=\""+Ctrl('c_nro_doc').GetCValue()+"\" />");
		  if(cuilRes.flag == "1")
		  {
		    alert('El CUIL ingresado ya se encuentra registrado');
		    Ctrl('c_nro_cuil').SetXValue('');	    
		    return false;
		  }
		}

	  var cuil;
	  cuil = Ctrl('c_nro_cuil').GetXValue();
	  cuil = cuil.replace('-', "");
	  if(cuil.length == 11) {
	    var ppio, medio, fin;
	    ppio = cuil.substr(0,2);
	    medio = cuil.substr(2,8);
	    fin = cuil.substr(10,1);
	    cuil = ppio + '-' + medio + '-' + fin;
	    Ctrl('c_nro_cuil').SetXValue(cuil);
	  }
	  else
	    Ctrl('c_nro_cuil').SetError("El ç del cuil es incorrecto.");
	}
}

function SetSexo()
{  
  if(Ctrl('c_sexo'))
  	Ctrl('c_sexo_hid').SetXValue(Ctrl('c_sexo').GetXValue());
}

function nombreyapellido()
{

  Ctrl('d_ape_y_nom').SetCValue(Ctrl('d_apellido').GetCValue()+', '+Ctrl('d_nombres').GetCValue());
}

function Save()
{

  if (Ctrl('main').GetMode()=="NEW")
  {
    //Si el tipo de documento es DNI saca los puntos y controla que sean solo numeros
    var dni = Ctrl('c_nro_doc').GetXValue();
    dni = Replace(dni, '.', "");
    Ctrl('c_nro_doc').SetXValue(dni);
    if (Ctrl('oi_tipo_documento').GetXValue() == 1) {
      if (Ctrl('c_nro_doc').GetXValue().length != 7 && Ctrl('c_nro_doc').GetXValue().length != 8) {
        alert("El largo del Documento es incorrecto");
        return false;
      }
      if (parseInt(dni, 10).toString() != Ctrl('c_nro_doc').GetXValue()) {
        alert("El Documento debe ser numérico");
        return true;
      }
    }
    if (val_doc())
    {
      Ctrl('c_cv_hid').SetCValue(Ctrl('c_cv').GetCValue());
      if(Ctrl('c_nro_cuil_hid').GetXValue() != "")
      {
        if(val_cuil())
        {
          Ctrl('f_actualizacion_hid').SetXValue(datetime2str(new Date()));
          Ctrl('f_alta_cv_hid').SetXValue(datetime2str(new Date()));
          Ctrl('main').DoEvent('SAVE');
        }
      }
      else
      {
        Ctrl('f_actualizacion_hid').SetXValue(datetime2str(new Date()));
        Ctrl('f_alta_cv_hid').SetXValue(datetime2str(new Date()));
        Ctrl('main').DoEvent('SAVE');
      }
    } 
    //Actualizo Fecha de alta del CV
    Ctrl('f_alta_cv_hid').SetXValue(datetime2str(new Date()));
  }
  //Actualizo fecha 
  Ctrl('f_actualizacion_hid').SetXValue(datetime2str(new Date()));

  if (Ctrl('main').GetMode()=="EDIT")
  {
    if(Ctrl('c_nro_cuil_hid').GetXValue() != "")
    { 
    	if(val_cuil())
     	{        
     	 Ctrl('f_actualizacion_hid').SetCValue(datetime2str(new Date()));
       Ctrl('main').DoEvent('SAVE');
      }
    }
    else
    	Ctrl('main').DoEvent('SAVE');
  }
  return true;
}

function val_f_nacim (myThis)
{  
  if (myThis.GetXValue() != "")
  {         
    if (myThis.GetXValue() >= date2str(NowDate()))
    {
      myThis.SetError('La fecha de Nacimiento debe ser anterior a Hoy');
      return false;
    }

    else return true;
    var anio = str2number(myThis.GetXValue().substr(0,4));
    anio = anio + 18;
    var fecha = number2str(anio);
    fecha += myThis.GetXValue().substr(4,2);
    fecha += myThis.GetXValue().substr(6,2);
    if (date2str(Now()) <= fecha)
    {
      myThis.SetError('La persona debe ser mayor de edad');
      return false;
    }
    else return true;
  }
  else return true;
}

function val_cuil()
{
  pstrCuil = Ctrl('c_nro_cuil_hid').GetXValue();
  var lngSexo;
  var strSexoyDocumento;
  var lngVerificador;

  var re = /-/g;
  pstrCuil = pstrCuil.replace( re, "" );
  if ( pstrCuil.length != 11 )
  {
    alert('El largo del cuil es incorrecto');
    return false;
  }

  if (!allDigits(pstrCuil))
  {
    alert('El cuil tiene caracteres inválidos');
     return false;
  }

  lngSexo = parseInt( pstrCuil.substr( 0, 2 ) );
  strSexoyDocumento = pstrCuil.substr( 0, 10 );
  lngVerificador = parseInt( pstrCuil.substr( pstrCuil.length - 1, 1 ) );

  if ( intDigVerificador(strSexoyDocumento) != lngVerificador )
  {
    alert('El dígito verificador del Cuil es Incorrecto');
    return false;
  }
  return true;
}

function intDigVerificador( pstrCuil )
{
    var dblSuma;
    var lngResto;
    var intDigVerificador;

    dblSuma = parseInt(pstrCuil.substr(0, 1)) * 5;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(1, 1)) * 4;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(2, 1)) * 3;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(3, 1)) * 2;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(4, 1)) * 7;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(5, 1)) * 6;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(6, 1)) * 5;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(7, 1)) * 4;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(8, 1)) * 3;
    dblSuma = dblSuma + parseInt(pstrCuil.substr(9, 1)) * 2;

    lngResto = dblSuma % 11;
    if (lngResto == 0)
    {
      return 0;
    }
    else
    {
      return parseInt(11 - lngResto);
    }
  }

function allDigits( str )
{
  var justDigits=false;

  if(typeof str!='string') return false;
  if(str.length==0) return false;

  for( var i=0; i<str.length; i++ )
  {
    d=str.charAt(i)
    if ((d<'0') || (d>'9')) return false;
  }
  return true;
}

function val_doc()
{
  var cv;  
  var nSQL = GetProxy().SQLService();

  cv = nSQL.GetOBJ(Ctrl("main").getResource("QRY_VAL_CV"), "<PARAM c_nro_doc=\""+Ctrl('c_nro_doc').GetCValue()+"\" />");
  if(cv.flag == "1")
  {
    alert('El CV ingresado ya se encuentra registrado');
    return false;
  }
  else
    return true;
}


function SetEdad()
{
	if(Ctrl("edad") && Ctrl('f_nacim'))
	{
		var fecha = new Date(str2date(Ctrl('f_nacim').GetXValue()));
		var hoy = new Date();		 
		var edad = parseInt(hoy.getFullYear() - fecha.getFullYear());
		if (hoy.getMonth() < fecha.getMonth())
			edad = edad -1;
		if (hoy.getMonth() == fecha.getMonth() && hoy.getDate() < fecha.getDate())
			edad = edad -1;
		//var edad = parseInt((hoy - fecha)/365/24/60/60/1000);		
		if(Ctrl('f_nacim').GetXValue() != "")
			Ctrl("edad").SetCValue(edad);
		else
			Ctrl("edad").SetCValue('');
	}
}    

function ActivarCV()
{	  
  Ctrl("f_estado").SetXValue(datetime2str(new Date()));
  Ctrl("f_actualizacion_hid").SetXValue(datetime2str(new Date()));	
  Ctrl("main").DoEvent("SetActive");                            
}

function InactivarCV()
{
	Ctrl("f_estado").SetXValue(datetime2str(new Date())); 
	Ctrl("f_actualizacion_hid").SetCValue(datetime2str(new Date()));
	Ctrl("main").DoEvent("SetInactive");                  

}   

function clickLista()
{

	if (Ctrl('main').GetMode() == 'LIST')
	{ 
	  if(Ctrl('LIST').GetSelectAttrValue('c_estado') == 'A')
		{	
			CtrlEnabled('INACTIVO',true); 
			CtrlEnabled('ACTIVO',false);
		}	
		else
		{	
			CtrlEnabled('ACTIVO',true);
			CtrlEnabled('INACTIVO',false);
		}	
	}
}  

function SetPersona()
{
   	if (Ctrl('main').GetMode() == 'NEW')
	{ 
	if(Ctrl("oi_personal") && Ctrl("oi_personal").GetXValue()!="")
	{                                       
	  var persona;				
		np = new NomadProxy("", ut);
		var nSQL = np.SQLService();   
		persona = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PERSONA"), "<PARAM oi_personal=\""+Ctrl("oi_personal").GetXValue()+"\" />"); 		

		Ctrl("d_apellido").SetXValue(persona.d_apellido); 
		Ctrl("d_nombres").SetXValue(persona.d_nombres); 
		Ctrl("oi_tipo_documento").SetXValue(persona.oi_tipo_documento); 
		Ctrl("c_nro_doc").SetXValue(persona.c_nro_documento); 
		if(persona.c_sexo && Ctrl("c_sexo"))
			Ctrl("c_sexo").SetXValue(persona.c_sexo); 
		if(persona.c_nro_cuil && Ctrl("d_calle"))
			Ctrl("c_nro_cuil").SetXValue(persona.c_nro_cuil);
		if(persona.oi_estado_civil && Ctrl("oi_estado_civil"))
			Ctrl("oi_estado_civil").SetXValue(persona.oi_estado_civil); 
		if(persona.f_nacim && Ctrl("f_nacim"))
			Ctrl("f_nacim").SetXValue(persona.f_nacim);
		if(persona.oi_docum_dig_per && Ctrl("oi_doc_digital"))
			Ctrl("oi_doc_digital").SetXValue(persona.oi_docum_dig_per);
		/*if(persona.oi_foto)
			Ctrl("oi_foto").SetCValue(persona.oi_foto);*/
		if(persona.d_calle && Ctrl("d_calle"))
			Ctrl("d_calle").SetCValue(persona.d_calle);
		if(persona.e_numero && Ctrl("c_nro"))
			Ctrl("c_nro").SetXValue(persona.e_numero);
		if(persona.d_piso && Ctrl("c_piso"))
			Ctrl("c_piso").SetXValue(persona.d_piso);
		if(persona.d_departamento && Ctrl("c_departamento"))
			Ctrl("c_departamento").SetXValue(persona.d_departamento);
		if(persona.oi_pais && Ctrl("oi_pais"))
			Ctrl("oi_pais").SetXValue(persona.oi_pais);		
		if(persona.oi_provincia && Ctrl("oi_provincia"))
			Ctrl("oi_provincia").SetXValue(persona.oi_provincia); 
		if(persona.d_localidad && Ctrl("d_localidad"))
			Ctrl("d_localidad").SetXValue(persona.d_localidad); 
		if(persona.c_postal && Ctrl("c_codigo_postal"))
			Ctrl("c_codigo_postal").SetXValue(persona.c_postal);		                                         
		if(persona.te_1 && Ctrl("te_nro"))
			Ctrl("te_nro").SetXValue(persona.te_1);
    if(persona.te_celular && Ctrl("te_celular"))
    	Ctrl("te_celular").SetXValue(persona.te_celular);
    if(persona.d_email && Ctrl("d_email"))
    	Ctrl("d_email").SetXValue(persona.d_email);     

   	codigocv(); 
		nombreyapellido();

	}
	else
	{
		clearCampos();
	}  
	}
}

